1	export type Customer = {
2	  yearsWithMHPCO: number;
3	};
4	
5	export type Item = {
6	  type: string;
7	};
8	
9	export type QuoteStep = {
10	  op: "quote";
11	  items: Item[];
12	};
13	
14	export type Step = QuoteStep;
15	
16	export type Scenario = {
17	  customer: Customer;
18	  steps: Step[];
19	};
20	
21	export type QuoteResult = {
22	  premium: number;
23	};
24	
25	export type Result = QuoteResult;
26	
27	const PROCESSING_FEE = 5;
28	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
29	
30	const BASE_PREMIUMS: Record<string, number> = {
31	  sword: 100,
32	  amulet: 60,
33	  staff: 80,
34	  potion: 40,
35	  rune: 25,
36	};
37	
38	const sumBasePremiums = (items: Item[]): number =>
39	  items.reduce((total, item) => total + BASE_PREMIUMS[item.type], 0);
40	
41	const quotePremium = (items: Item[]): number => {
42	  const basePremium = sumBasePremiums(items);
43	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
44	  return basePremium + firstInsuranceSurcharge + PROCESSING_FEE;
45	};
46	
47	export const processScenario = (scenario: Scenario): { results: Result[] } => {
48	  return { results: [{ premium: quotePremium(scenario.steps[0].items) }] };
49	};
